	@Test
	void parentCostsEachCanonicalChildCombinationOnceAcrossUnrelatedWakeUps() {
		StatementPattern child = pattern();
		Filter root = new Filter(child, new Bound(Var.of("o")));
		ParentCombinationCostModel costModel = new ParentCombinationCostModel();
		RuleRegistry rules = RuleRegistry.builder()
				.add(new TestImplementationRule())
				.add(new LateChildWinnerAndProofRule(child))
				.build();

		CascadesPlan plan = new CascadesPlanner(costModel, rules, CascadesTelemetry.NO_OP)
				.optimize(root, OptimizationGoal.root());

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness());
		assertEquals(Map.of("initial", 1, "late", 1), costModel.parentCostApplications(),
				"An unrelated child proof wake must not recost an existing combination, while the late child winner "
						+ "must add exactly one new combination");
		assertTrue(plan.winner()
				.orElseThrow()
				.proofs()
				.stream()
				.anyMatch(proof -> "late-child-winner-and-proof".equals(proof.ruleId())));
		List<RejectedAlternative> rejections = plan.provenance().orElseThrow().rejectedAlternatives();
		assertTrue(!rejections.isEmpty(), "The deliberately dominated parent implementation must be diagnosed");
		Set<String> rejectionClasses = new LinkedHashSet<>();
		for (RejectedAlternative rejection : rejections) {
			rejectionClasses.add(rejection.ruleId() + '|' + rejection.reason() + '|' + rejection.missingProperties());
		}
		assertEquals(rejectionClasses.size(), rejections.size(),
				"Repeated dominated evaluations must not duplicate one rule/reason/missing-property diagnostic class");
		assertEquals(Map.of("initial", 2, "late", 2), costModel.parentDeliveredApplications(),
				"Each of the two distinct physical parent implementations must be prepared once per canonical child "
						+ "combination, without preparation on unrelated replay");
	}

