		assertNotNull(state.beginCostApplication(memo, parentPhysical, goal, List.of(first)));
		assertNull(state.beginCostApplication(memo, parentPhysical, goal, List.of(equivalent)),
				"Equivalent immutable winner states must identify one cost application");
