	@Test
	void firstEstimateForNewContextDoesNotInvalidateExistingContextWinner() {
		Memo memo = new Memo(CascadesCostModel.from(new EvaluationStatistics()));
		StatementPattern pattern = pattern();
		int groupId = memo.intern(pattern);
		MemoExpr physical = memo.addPhysicalAlternative(groupId, pattern.clone(), PhysicalProperties.ANY,
				"context-estimate", RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of()).orElseThrow();
		drainChanges(memo);

		OptimizationGoal existingGoal = OptimizationGoal.root();
		Winner existingWinner = new Winner(physical, pattern.clone(), PhysicalProperties.ANY, exactCost(10.0d),
				List.of(), false, "");
		assertTrue(memo.addWinner(existingGoal.key(groupId), existingWinner, 8, true));
		drainChanges(memo);

		OptimizationGoal newContext = OptimizationGoal.root()
				.withInputBindingContext(InputBindingContext.fromProfile(3.0d, Set.of("s"), BindingProfile.ANY));
		LogicalOutputEstimateKey estimateKey = LogicalOutputEstimateKey.of(newContext, 0L);
		memo.mergeLogicalOutputEstimate(groupId, physical.id(), estimateKey,
				LogicalOutputEstimate.from(exactCost(3.0d)));

		assertTrue(memo.bestWinner(existingGoal.key(groupId)).isPresent(),
				"Installing an estimate for a new context must not invalidate another context's winner");
		assertTrue(memo.logicalOutputEstimate(groupId, estimateKey).isPresent(),
				"The new context must retain its canonical logical estimate");
		assertFalse(memo.hasPendingChanges(),
				"A first context-local estimate must not emit a group-global cost-estimate wake-up");
	}

	@Test
	void exactFiniteFactsWinEqualQualityLogicalEstimateConflict() {
		BindingProfile exactFiniteProfile = new BindingProfile(Map.of(), Map.of(),
				Map.of("value", FiniteDomainFact.exact(
						List.of(SimpleValueFactory.getInstance().createLiteral(50)), true, "exact-values")),
				Map.of(), Map.of(), Set.of(), Map.of(), BindingProfile.ANY_ENDPOINT_MODE, null);
		LogicalOutputEstimate selective = LogicalOutputEstimate.from(exactCost(3.0d), exactFiniteProfile);
		LogicalOutputEstimate broad = LogicalOutputEstimate.from(exactCost(24_830.0d), BindingProfile.ANY);

		assertEquals(selective, broad.stronger(selective),
				"Exact finite facts must outrank a broader fact-free estimate of otherwise equal quality");
		assertEquals(selective, selective.stronger(broad),
				"Canonical evidence election must not depend on physical-alternative discovery order");
	}

	@Test
	void ruleApplicationIdentityUsesOnlyDeclaredGoalDependencies() {
		CascadesPlanner.SearchState state = new CascadesPlanner.SearchState(Integer.MAX_VALUE,
				OptimizationGoal.SearchMode.EXACT);
		RuleDescriptor cardinalityInvariant = RuleDescriptor.builder("cardinality-invariant", RuleKind.TRANSFORMATION)
				.build();
		RuleDescriptor cardinalitySensitive = RuleDescriptor.builder("cardinality-sensitive", RuleKind.IMPLEMENTATION)
				.goalPropertiesRead(RuleDescriptor.GoalProperty.INVOCATION_CARDINALITY)
				.build();
		OptimizationGoal oneInvocation = OptimizationGoal.root()
				.withInputBindingContext(InputBindingContext.fromProfile(1.0d, Set.of("s"), BindingProfile.ANY));
		OptimizationGoal manyInvocations = OptimizationGoal.root()
				.withInputBindingContext(InputBindingContext.fromProfile(10_000.0d, Set.of("s"), BindingProfile.ANY));
		OptimizationGoal differentBindings = OptimizationGoal.root()
				.withInputBindingContext(InputBindingContext.fromProfile(1.0d, Set.of("o"), BindingProfile.ANY));

		assertEquals(state.ruleApplicationGoal(oneInvocation, cardinalityInvariant),
				state.ruleApplicationGoal(manyInvocations, cardinalityInvariant),
				"An invariant rule saturates once for the same semantic binding shape");
		assertNotEquals(state.ruleApplicationGoal(oneInvocation, cardinalityInvariant),
				state.ruleApplicationGoal(differentBindings, cardinalityInvariant),
				"A different assured-binding shape can enable another alternative");
		assertNotEquals(state.ruleApplicationGoal(oneInvocation, cardinalitySensitive),
				state.ruleApplicationGoal(manyInvocations, cardinalitySensitive),
				"A rule that prices access paths retains invocation cardinality in its ledger identity");
	}

	private static StatementPattern pattern() {
		return new StatementPattern(Var.of("s"), Var.of("p"), Var.of("o"));
	}

	private static CostVector exactCost(double rows) {
		return exactCost(rows, rows);
	}

	private static CostVector exactCost(double rows, double workRows) {
		return new CostVector(rows, workRows, 0.0d, 0.0d, 0.0d, 1.0d, 1.0d);
	}

	private static void drainChanges(Memo memo) {
		while (memo.pollChange().isPresent()) {
			// Drain setup changes so each assertion observes only the operation under test.
		}
	}

	private static final class TestImplementationRule implements CascadesRule {

		@Override
		public String id() {
			return "cost-ledger-implementation";
		}

		@Override
		public RuleKind kind() {
			return RuleKind.IMPLEMENTATION;
		}

		@Override
		public RuleDescriptor descriptor() {
			return RuleDescriptor.builder(id(), kind())
					.rootOperators(RuleRootOperator.STATEMENT_PATTERN, RuleRootOperator.FILTER)
					.wakeUpEvents(RuleWakeUpEvent.LOGICAL_EXPRESSION_ADDED)
					.convergenceClass(RuleConvergenceClass.FINITE_EQUIVALENCE_EXPANSION)
					.build();
		}

		@Override
		public boolean matches(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return expression.logical()
					&& (expression.tupleExpr() instanceof StatementPattern
							|| expression.tupleExpr() instanceof Filter);
		}

		@Override
		public int promise(MemoExpr expression, OptimizationGoal goal, Memo memo) {
			return 10;
		}

		@Override
		public List<RuleApplication> apply(MemoExpr expression, OptimizationGoal goal, RuleContext context) {
			RuleProof proof = proof(expression, goal, context);
			if (expression.tupleExpr() instanceof StatementPattern) {
				PhysicalProperties delivered = goal.requiredProperties().withAccessPath("initial");
				return List.of(RuleApplication.physical(expression.groupId(), expression.tupleExpr().clone(), delivered,
						exactCost(10.0d), proof, "initial-child"));
			}
			if (((Filter) expression.tupleExpr()).getCondition() instanceof Exists) {
				return List.of(RuleApplication.physical(expression.groupId(), expression.tupleExpr().clone(),
						PhysicalProperties.ANY, CostVector.ZERO, proof, "dependent-parent"));
			}
			return List.of(
					RuleApplication.physical(expression.groupId(), expression.tupleExpr().clone(),
							PhysicalProperties.ANY,
							CostVector.ZERO, proof, "parent-primary"),
					RuleApplication.physical(expression.groupId(), expression.tupleExpr().clone(),
							PhysicalProperties.ANY,
							exactCost(1.0d, 1_000.0d), proof, "parent-dominated"));
		}
	}

